1	//! Report data type and rendering (matches the oracle's WARNING comment).
2	
3	use std::collections::BTreeSet;
4	
5	/// One topic block of the wellformedness report: a header `topic` and the
6	/// already-formatted `message` body that appears beneath its underline.
7	#[derive(Debug, Clone, PartialEq)]
8	pub struct WfError {
9	    pub topic: String,
10	    pub message: String,
11	}
12	
13	impl WfError {
14	    pub fn new(topic: impl Into<String>, message: impl Into<String>) -> Self {
15	        WfError {
16	            topic: topic.into(),
17	            message: message.into(),
18	        }
19	    }
20	}
21	
22	pub type WfReport = Vec<WfError>;
23	
24	/// The success line the oracle prints when no check fails.
25	pub const SUCCESS_LINE: &str = "/* All wellformedness checks were successful. */";
26	
27	/// A topic header formatted exactly as the oracle renders it: the title on one
28	/// line, then `=` repeated to the title's (character) length on the next.
29	pub fn underline_topic(title: &str) -> String {
30	    let n = title.chars().count();
31	    let bar: String = std::iter::repeat('=').take(n).collect();
32	    format!("{}\n{}", title, bar)
33	}
34	
35	/// The set of distinct topics present in a report.
36	pub fn topics(report: &WfReport) -> BTreeSet<String> {
37	    report.iter().map(|e| e.topic.clone()).collect()
38	}
39	
40	/// Render one topic block: header + underline + blank line + body.
41	fn render_block(topic: &str, message: &str) -> String {
42	    format!("{}\n\n{}", underline_topic(topic), message)
43	}
44	
45	/// Separator between two individual findings that share a topic block. Every
46	/// grouped-list topic the checker emits uses this separator (a blank line whose
47	/// only content is two spaces), so the block layer can rejoin per-finding
48	/// entries into the byte-exact bundled body.
49	pub const FINDING_SEP: &str = "\n  \n";
50	
51	/// Merge CONSECUTIVE same-topic findings into one `(topic, body)` block,
52	/// joining their bodies with [`FINDING_SEP`]. The report holds one entry PER
53	/// FINDING (so `report.len()` is the oracle's finding count); a topic that
54	/// recurs after an intervening different topic starts a fresh block (this is
55	/// what the interleaved formula-check bundle relies on).
56	fn group_findings(report: &WfReport) -> Vec<(String, String)> {
57	    let mut out: Vec<(String, String)> = Vec::new();
58	    for e in report {
59	        match out.last_mut() {
60	            Some((topic, body)) if *topic == e.topic => {
61	                body.push_str(FINDING_SEP);
62	                body.push_str(&e.message);
63	            }
64	            _ => out.push((e.topic.clone(), e.message.clone())),
65	        }
66	    }
67	    out
68	}
69	
70	/// Render a full report as the oracle's WARNING comment (byte-identical), or
71	/// the success line for an empty report. Per-finding entries sharing a topic
72	/// are grouped into a single block (see [`group_findings`]).
73	pub fn render_report(report: &WfReport) -> String {
74	    if report.is_empty() {
75	        return SUCCESS_LINE.to_string();
76	    }
77	    let blocks: Vec<String> = group_findings(report)
78	        .iter()
79	        .map(|(t, m)| render_block(t, m))
80	        .collect();
81	    let inner = format!(
82	        "WARNING: the following wellformedness checks failed!\n\n{}",
83	        blocks.join("\n\n")
84	    );
85	    format!("/*\n{}\n*/", inner)
86	}
87	
88	/// Insert `errors` into `report` immediately before the first entry whose topic
89	/// is one of `anchors`. If no anchor is present, append at the end.
90	pub fn insert_wf_before(report: &mut Vec<WfError>, errors: Vec<WfError>, anchors: &[&str]) {
91	    if errors.is_empty() {
92	        return;
93	    }
94	    match report
95	        .iter()
96	        .position(|e| anchors.iter().any(|a| *a == e.topic))
97	    {
98	        Some(i) => {
99	            let tail = report.split_off(i);
100	            report.extend(errors);
101	            report.extend(tail);
102	        }
103	        None => report.extend(errors),
104	    }
105	}
