779	/// Format the `/* WARNING: ... */` or `/* All wellformedness checks
780	/// were successful. */` block that goes BETWEEN the source body and
781	/// the analysis summary.  Mirrors HS's `prettyWfErrorReport`
782	/// (Wellformedness.hs:118-125).
783	///
784	/// Each `WfError.message` is expected to carry the FULL HS-style block
785	/// for its topic: `Title\n=====\n\n<intro>\n<body>` — pre-formatted with
786	/// the exact bytes HS emits, including trailing spaces from HS's
787	/// `text ""` markers.  Multiple `WfError`s with the same topic are
788	/// merged into one block (the per-clash bodies concatenated).  Topic
789	/// groups are separated by blank lines.
790	///
791	/// Shared by the `--prove` CLI (`run.rs`) and the interactive web server
792	/// (`source`/`message` routes) so both render the wellformedness comment
793	/// byte-identically.  The empty-report case returns exactly
794	/// `"/* All wellformedness checks were successful. */"`, so no-warning
795	/// theories stay byte-for-byte unchanged on both paths.
796	pub fn format_wf_block(report: &[tamarin_parser::wf::WfError]) -> String {
797	    if report.is_empty() {
798	        return "/* All wellformedness checks were successful. */".to_string();
799	    }
800	    let mut out = String::new();
801	    out.push_str("/*\nWARNING: the following wellformedness checks failed!\n\n");
802	    out.push_str(&render_wf_error_report(report));
803	    // Trim trailing blank lines but keep a single newline before `*/`.
804	    while out.ends_with("\n\n") { out.pop(); }
805	    out.push_str("*/");
806	    out
807	}
808	
809	/// Bare `prettyWfErrorReport` rendering (Wellformedness.hs:118-125) —
810	/// the grouped topic blocks WITHOUT the `/* WARNING ... */` comment
811	/// wrapper.  Shared by `format_wf_block` (batch theory output) and the
812	/// interactive server's `ppInteractive` console echo of the report at
813	/// theory-load time (Web/Dispatch.hs:149-209, see line 187,200-209).
814	// grouped by topic; OUTPUT order driven by the topic_order Vec, map keyed only;
815	// std kept (byte-inert) — iteration order never reaches output.
816	#[allow(clippy::disallowed_types)]
817	pub fn render_wf_error_report(report: &[tamarin_parser::wf::WfError]) -> String {
818	    let mut out = String::new();
819	    // Group by topic, preserving FIRST-APPEARANCE order — mirrors HS's
820	    // `groupOn fst` over a left-to-right concatMap-over-checks.
821	    let mut topic_order: Vec<&str> = Vec::new();
822	    let mut grouped: std::collections::HashMap<&str, Vec<&str>> =
823	        std::collections::HashMap::new();
824	    for e in report {
825	        if !grouped.contains_key(e.topic.as_str()) {
826	            topic_order.push(e.topic.as_str());
827	        }
828	        grouped.entry(e.topic.as_str()).or_default().push(&e.message);
829	    }
830	    for (i, topic) in topic_order.iter().enumerate() {
831	        let msgs = &grouped[topic];
832	        if i > 0 { out.push('\n'); }
833	        // HS `prettyWfErrorReport` (Wellformedness.hs:118-125) groups by
834	        // topic and renders each group as
835	        //   `text topic $-$ (nest 2 . vcat . intersperse (text "") $ bodies)`
836	        // — the underlineTopic header ONCE per group, then the 2-space-nested
837	        // bodies separated by a 2-space blank line.  Most RS checks already
838	        // pre-render the FULL block (header + indent) into a single per-topic
839	        // message, and we concatenate those as-is (legacy path, unchanged).
840	        //
841	        // Some checks emit one HEADER-LESS body per offending rule (so the
842	        // summary's `length rep` WARNING count stays HS-faithful,
843	        // Batch.hs:87-316, see line 245), all sharing one topic.  These are assembled HS-style
844	        // (`prettyWfErrorReport`, Wellformedness.hs:118-125): the topic header
845	        // (+ any "reasons" preamble that HS folds into the topic string) ONCE,
846	        // then the per-rule bodies joined by the `intersperse (text "")`
847	        // 2-space blank separator.  Other (single-entry) topics keep baking
848	        // their full block into the message (default path below).
849	        if let Some(preamble) = wf_headerless_preamble(topic) {
850	            out.push_str(&preamble);
851	            out.push_str(&msgs.join("\n  \n"));
852	            out.push('\n');
853	        } else {
854	            for (j, m) in msgs.iter().enumerate() {
855	                if j > 0 { out.push('\n'); }
856	                out.push_str(m);
857	                if !m.ends_with('\n') { out.push('\n'); }
858	            }
859	        }
860	    }
861	    out
862	}
