864	/// For the WF topics whose checks emit one header-less body per finding,
865	/// return the byte-exact preamble that `prettyWfErrorReport` prints ONCE
866	/// before the group's bodies: the `underlineTopic` header plus the blank
867	/// line HS's `$-$` folds in between the header and the first body
868	/// (Wellformedness.hs:118-125).  Returns `None` for single-entry topics,
869	/// which bake their full block into the message (default path).
870	fn wf_headerless_preamble(topic: &str) -> Option<String> {
871	    use tamarin_parser::wf::underline_topic;
872	    match topic {
873	        // SAPIC-process wellformedness errors (HS `toWfErrorReport`,
874	        // Warnings.hs:23-26).  Unlike the other topics, HS does NOT underline
875	        // this one — `prettyWfErrorReport` renders it as a bare `text topic`
876	        // (Wellformedness.hs:118-125, see line 124).  So the per-error bodies (each
877	        // `"  Variable bound twice: x."`) sit directly under a plain header.
878	        "Wellformedness-error in Process" => Some(format!("{topic}\n")),
879	        // Header-less-body topics: HS underlines each and separates the header
880	        // from the first body with a blank line (`underlineTopic $-$ body`,
881	        // Wellformedness.hs:118-125).  The "mismatching sorts" body already
882	        // carries its own "Possible reasons:" preamble from the checker
883	        // (Wellformedness.hs:258-273), so the assembly supplies only the
884	        // underline and the blank line here — never a second copy.
885	        "Unbound variables"
886	        | "Special facts"
887	        | "Reserved names"
888	        | "Public constants with mismatching capitalization"
889	        | "Variable with mismatching sorts or capitalization"
890	        | "Fact capitalization issues"
891	        | "Fact arity issues"
892	        | "Quantifier sorts"
893	        | "Formula terms"
894	        | " Formula guardedness"
895	        | "Lemma annotations"
896	        | "Check presence of the --prove/--lemma arguments in theory"
897	        | "Facts occur in the left-hand-side but not in any right-hand-side " => {
898	            Some(format!("{}\n\n", underline_topic(topic)))
899	        }
900	        _ => None,
901	    }
902	}
