904	/// HS `ppNonEmptyList' name pp xs = (keyword_ name <->) . fsep $
905	/// punctuate comma (map pp xs)` (Term/Maude/Signature.hs:229-231).
906	/// `<->` is HughesPJ `<+>` (beside-with-space), and `fsep` is the
907	/// fill-paragraph combinator, so the wrap decisions must come from the
908	/// ported HughesPJ Doc engine (LINE_LENGTH=110, RIBBON=73) — not a
909	/// hand-rolled greedy fill at a guessed width.  Route through `pretty_hpj`.
910	fn wrap_with_lead<S: AsRef<str>>(lead: &str, items: &[S]) -> String {
911	    use crate::pretty_hpj::{self as hpj, Doc};
912	    if items.is_empty() { return String::new(); }
913	    let docs: Vec<Doc> = items.iter().map(Doc::text).collect();
914	    let body = hpj::fsep(hpj::punctuate(Doc::char(','), docs));
915	    // HS `ppNonEmptyList' name = (keyword_ name <->) . fsep`
916	    // (Term/Maude/Signature.hs:220-247, see line 229) — the `builtins:`/`functions:` lead is a
917	    // keyword.  `keyword_` is the identity in plain mode, so `--prove` is
918	    // unchanged.
919	    hpj::keyword_(lead).beside_sp(body).render()
920	}
921	
922	/// HS `equations:` layout (Term/Maude/Signature.hs:224-225):
923	///   `P.sep ( keyword_ "equations:" : map (P.nest 2) ds )`
924	/// where `ds = P.punctuate P.comma (map prettyCtxtStRule rules)` — i.e. the
925	/// comma is appended to the END of each equation doc (all but the last), and
926	/// each resulting doc is `nest 2`'d, then `sep`-joined.
927	///
928	/// Each equation doc is itself (SubtermRule.hs:121-123):
929	///   `prettyCtxtStRule r = sep [ nest 2 (prettyLNTerm lhs)
930	///                             , operator_ "=" <-> prettyLNTerm rhs ]`
931	/// — so the LHS carries an *inner* `nest 2`.  When the outer `sep` breaks and
932	/// lays each equation on its own line at indent 2, the inner `nest 2` adds a
933	/// further 2, yielding the 4-space indent HS emits.  Reproducing that requires
934	/// the structured doc, not a pre-joined `lhs = rhs` string.  Route through the
935	/// ported HughesPJ engine so the break decision and indentation are HS-exact.
936	///
937	/// `items` carries the LHS/RHS as already-built term `Doc`s (HS `prettyLNTerm`)
938	/// so the inner function-application `fsep` wrapping survives — passing flat
939	/// strings would defeat the engine and emit over-long single lines for wide
940	/// equations (e.g. BP `idverify(idsign(…), m, IBPub(…))`).
941	fn sep_block_with_lead(lead: &str, items: &[(crate::pretty_hpj::Doc, crate::pretty_hpj::Doc)]) -> String {
942	    use crate::pretty_hpj::{self as hpj, Doc};
943	    if items.is_empty() { return String::new(); }
944	    let n = items.len();
945	    let mut docs: Vec<Doc> = Vec::with_capacity(n + 1);
946	    // HS `keyword_ "equations:"` / `keyword_ "equations [convergent]:"`
947	    // (Term/Maude/Signature.hs:220-247, see line 225).  Identity in plain mode.
948	    docs.push(hpj::keyword_(lead));
949	    for (i, (lhs, rhs)) in items.iter().enumerate() {
950	        // prettyCtxtStRule: sep [ nest 2 lhs, operator_ "=" <-> rhs ]
951	        let lhs_doc = lhs.clone().nest(2);
952	        let eq_doc = hpj::operator_("=").beside_sp(rhs.clone());
953	        let mut d = hpj::sep(vec![lhs_doc, eq_doc]);
954	        if i + 1 < n {
955	            d = d.beside(Doc::char(','));
956	        }
957	        docs.push(d.nest(2));
958	    }
959	    hpj::sep(docs).render()
960	}
